/*
======================================================================
Design System
======================================================================
*/

:root {
    /* Brand & palette */
    --color-primary-red: #E02020; /* logo red */
    --color-primary-dark: #333333; /* headings, primary text */
    --color-secondary: #777777; /* muted text */
    --color-secondary-light: #999999; /* meta text */
    --color-border: #CCCCCC; /* light borders */
    --color-border-soft: #E5E5E5; /* nav + subtle dividers */
    --color-bg: #FFFFFF; /* main background */
    --color-bg-muted: #F5F5F5; /* footer background */

    /* Typography */
    --font-heading: "Space Grotesk", Helvetica, sans-serif;
    --font-body: "Source Sans 3", Arial, sans-serif;

    --font-size-root: 16px;
    --font-size-h1: 2rem;      /* 32px */
    --font-size-h2: 1.5rem;    /* 24px */
    --font-size-h3: 1.125rem;  /* 18px */
    --font-size-body: 0.9375rem; /* 15px approx */
    --font-size-small: 0.75rem;  /* 12px */

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.7;

    /* Spacing scale */
    --space-xxs: 4px;
    --space-xs: 8px;
    --space-sm: 16px;
    --space-md: 24px;
    --space-lg: 32px;
    --space-xl: 48px;
    --space-xxl: 64px;

    /* Layout */
    --container-max-width: 1100px;
}

/*
======================================================================
Global
======================================================================
*/

*,
*::before,
*::after {
    box-sizing: border-box;
}

html {
    font-size: var(--font-size-root);
}

body.site {
    margin: 0;
    padding: 0;
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-primary-dark);
    background-color: var(--color-bg);
    -webkit-font-smoothing: antialiased;
}

img {
    max-width: 100%;
    height: auto;
    border: 0;
}

.container {
    width: 100%;
    max-width: var(--container-max-width);
    margin: 0 auto;
    padding-left: var(--space-md);
    padding-right: var(--space-md);
}

h1,
h2,
h3,
h4,
h5,
h6 {
    font-family: var(--font-heading);
    font-weight: 600;
    line-height: var(--line-height-tight);
    margin: 0 0 var(--space-sm);
}

p {
    margin: 0 0 var(--space-sm);
}

a {
    color: var(--color-primary-dark);
    text-decoration: none;
}

a:hover,
a:focus {
    text-decoration: underline;
}

.site-main-wrapper {
    padding-top: var(--space-xl);
    padding-bottom: var(--space-xl);
}

.site-content {
    min-height: 40vh;
}

/*
======================================================================
Header
======================================================================
*/

.site-header {
    background-color: var(--color-bg);
}

.header-top {
    border-bottom: 1px solid var(--color-border-soft);
    padding-top: var(--space-lg);
    padding-bottom: var(--space-lg);
}

.header-top-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

/* Logo */

.logo-link {
    display: inline-flex;
    align-items: center;
    gap: var(--space-sm);
    color: var(--color-primary-dark);
}

.logo-mark {
    position: relative;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: var(--space-xs) var(--space-sm);
}

.logo-text {
    font-family: var(--font-heading);
    font-weight: 700;
    font-size: 2rem;
    letter-spacing: 0.05em;
    color: var(--color-primary-red);
}

.logo-arrow {
    width: 6px;
    height: 36px;
    background-color: #B3B3B3;
    position: relative;
}

.logo-arrow--up {
    margin-right: var(--space-xs);
}

.logo-arrow--down {
    margin-left: var(--space-xs);
}

.logo-arrow--up::before,
.logo-arrow--down::after {
    content: "";
    position: absolute;
    left: 50%;
    transform: translateX(-50%);
    border-left: 6px solid transparent;
    border-right: 6px solid transparent;
}

.logo-arrow--up::before {
    top: -6px;
    border-bottom: 6px solid #B3B3B3;
}

.logo-arrow--down::after {
    bottom: -6px;
    border-top: 6px solid #B3B3B3;
}

.site-tagline {
    font-size: 0.8125rem;
    color: var(--color-secondary);
    letter-spacing: 0.06em;
    text-transform: uppercase;
}

/* Header contact */

.header-contact {
    text-align: right;
    font-size: 0.9375rem;
}

.header-phone {
    margin: 0 0 var(--space-xs);
    color: var(--color-secondary);
}

.header-phone strong {
    color: var(--color-primary-dark);
}

.header-email {
    margin: 0;
    font-size: 0.8125rem;
    color: var(--color-secondary-light);
    display: inline-flex;
    align-items: center;
    gap: 6px;
}

.email-icon {
    font-size: 0.75rem;
}

/*
======================================================================
Primary navigation
======================================================================
*/

.primary-nav {
    border-bottom: 1px solid var(--color-border-soft);
}

.primary-menu {
    margin: 0;
    padding: 0;
    list-style: none;
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
}

.menu-item {
    position: relative;
}

.menu-item + .menu-item {
    margin-left: var(--space-lg);
}

.menu-link {
    display: inline-block;
    padding-top: var(--space-sm);
    padding-bottom: var(--space-sm);
    font-size: 0.9375rem;
    color: var(--color-secondary);
}

.menu-link:hover,
.menu-link:focus {
    color: var(--color-primary-dark);
    text-decoration: none;
}

/* Active/current menu item underline */

.current-menu-item .menu-link {
    color: var(--color-primary-dark);
}

.current-menu-item .menu-link::after {
    content: "";
    position: absolute;
    left: 0;
    right: 0;
    bottom: -1px;
    margin: 0 auto;
    width: 60%;
    border-bottom: 2px solid var(--color-primary-dark);
}

/* Right-aligned items on larger screens, still part of same flex row */

.menu-item--right {
    /* visually they will appear after core items; no extra style needed for simplicity */
}

/*
======================================================================
Footer
======================================================================
*/

.site-footer {
    margin-top: var(--space-xl);
    font-size: 0.875rem;
    color: var(--color-secondary);
}

.footer-main {
    background-color: var(--color-bg-muted);
    border-top: 1px solid var(--color-border-soft);
    border-bottom: 1px solid var(--color-border-soft);
    padding-top: var(--space-xl);
    padding-bottom: var(--space-xl);
}

.footer-inner {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-xl);
}

.footer-column {
    min-width: 200px;
}

.footer-column--brand {
    flex: 2 1 40%;
}

.footer-column--links,
.footer-column--contact {
    flex: 1 1 25%;
}

.footer-logo {
    font-family: var(--font-heading);
    font-weight: 700;
    font-size: 1.125rem;
    margin-bottom: var(--space-sm);
    color: var(--color-primary-dark);
}

.footer-description {
    margin: 0;
    max-width: 360px;
}

.footer-heading {
    font-size: 0.9375rem;
    text-transform: uppercase;
    letter-spacing: 0.08em;
    margin-bottom: var(--space-sm);
    color: var(--color-primary-dark);
}

.footer-links {
    list-style: none;
    margin: 0;
    padding: 0;
}

.footer-links li + li {
    margin-top: var(--space-xs);
}

.footer-links a {
    color: var(--color-secondary);
}

.footer-links a:hover,
.footer-links a:focus {
    color: var(--color-primary-dark);
    text-decoration: none;
}

.footer-contact-line {
    margin: 0 0 var(--space-xs);
}

.footer-address {
    line-height: var(--line-height-relaxed);
}

.footer-bottom {
    background-color: var(--color-bg);
}

.footer-bottom-inner {
    padding-top: var(--space-md);
    padding-bottom: var(--space-md);
    text-align: center;
}

.footer-copy {
    margin: 0;
    font-size: var(--font-size-small);
    color: var(--color-secondary-light);
}

/*
======================================================================
Responsive
======================================================================
*/

@media (max-width: 900px) {
    .header-top-inner {
        flex-direction: column;
        align-items: flex-start;
        gap: var(--space-sm);
    }

    .header-contact {
        text-align: left;
    }

    .primary-menu {
        justify-content: flex-start;
    }

    .menu-item + .menu-item {
        margin-left: var(--space-md);
    }
}

@media (max-width: 640px) {
    .primary-menu {
        flex-direction: row;
        flex-wrap: wrap;
    }

    .menu-link {
        padding-top: var(--space-xs);
        padding-bottom: var(--space-xs);
        font-size: 0.875rem;
    }

    .footer-inner {
        flex-direction: column;
    }

    .footer-column {
        min-width: 0;
    }
}
